// Mock Firebase Auth
const mockAuth = {
  currentUser: null,
  signInWithEmailAndPassword: jest.fn(),
  signOut: jest.fn(),
  onAuthStateChanged: jest.fn()
};

// Mock Firestore
const mockDoc = {
  id: "test-doc-id",
  data: jest.fn(() => ({
    dosage: "20mg",
    name: "Test Medication",
    frequency: "daily"
  }))
};

const mockQuerySnapshot = {
  size: 1,
  docs: [mockDoc],
  forEach: jest.fn(callback => callback(mockDoc))
};

const mockCollection = jest.fn(() => ({
  add: jest.fn(() => Promise.resolve({ id: "test-doc-id" })),
  doc: jest.fn(() => ({
    get: jest.fn(() => Promise.resolve(mockDoc)),
    update: jest.fn(() => Promise.resolve())
  })),
  where: jest.fn(() => ({
    get: jest.fn(() => Promise.resolve(mockQuerySnapshot))
  }))
}));

const mockDb = {
  collection: mockCollection
};

// Export mocked Firebase services
export const auth = mockAuth;
export const db = mockDb;
export const collection = mockCollection;
export const doc = jest.fn(() => ({
  get: jest.fn(() => Promise.resolve(mockDoc)),
  update: jest.fn(() => Promise.resolve())
}));
export const getDoc = jest.fn(() => Promise.resolve(mockDoc));
export const getDocs = jest.fn(() => Promise.resolve(mockQuerySnapshot));
export const addDoc = jest.fn(() => Promise.resolve({ id: "test-doc-id" }));
export const updateDoc = jest.fn(() => Promise.resolve());
export const query = jest.fn(() => ({
  get: jest.fn(() => Promise.resolve(mockQuerySnapshot))
}));
export const where = jest.fn(() => ({
  get: jest.fn(() => Promise.resolve(mockQuerySnapshot))
}));
export const signInWithEmailAndPassword = jest.fn();
export const signOut = jest.fn();
